prompt --application/pages/page_00003
begin
wwv_flow_imp_page.create_page(
 p_id=>3
,p_name=>'Detalle Bar'
,p_alias=>'DETALLE-BAR'
,p_step_title=>'Detalle Bar'
,p_autocomplete_on_off=>'OFF'
,p_javascript_code_onload=>wwv_flow_string.join(wwv_flow_t_varchar2(
'const API_BASE = ''https://s9-g4-2026-1.onrender.com/bares'';',
'const barId = parseInt(apex.item(''P3_BAR_ID'').getValue());',
'',
'function cargarComentarios() {',
'  fetch(`${API_BASE}/${barId}/comentarios`)',
'    .then(res => res.json())',
'    .then(data => {',
'      const container = document.getElementById(''comentarios-container'');',
'      if (data.length === 0) {',
'        container.innerHTML = ''<p>No hay comentarios aun.</p>'';',
'        return;',
'      }',
'      container.innerHTML = data.map(c => `',
'        <div style="border:1px solid #ddd; border-radius:8px; padding:12px; margin-bottom:10px;">',
'          <strong>${c.autor || ''Anonimo''}</strong>',
'          <p style="margin-top:6px;">${c.texto}</p>',
'        </div>',
'      `).join('''');',
'    })',
'    .catch(() => {',
'      document.getElementById(''comentarios-container'').innerHTML = ''<p>Error cargando comentarios.</p>'';',
'    });',
'}',
'',
'function enviarComentario() {',
'  const texto = apex.item(''P3_TEXTO_COMENTARIO'').getValue();',
'  if (!texto.trim()) {',
'    apex.message.showErrors([{ message: ''El comentario no puede estar vacio.'' }]);',
'    return;',
'  }',
'  fetch(`${API_BASE}/${barId}/comentarios`, {',
'    method: ''POST'',',
'    headers: { ''Content-Type'': ''application/json'' },',
'    body: JSON.stringify({ bar_id: barId, texto: texto, autor: apex.env.APP_USER })',
'  })',
'  .then(res => res.json())',
'  .then(() => {',
'    apex.item(''P3_TEXTO_COMENTARIO'').setValue('''');',
'    cargarComentarios();',
'  });',
'}',
'',
'function cargarEventos() {',
'  fetch(`${API_BASE}/${barId}/eventos`)',
'    .then(res => res.json())',
'    .then(data => {',
'      const container = document.getElementById(''eventos-container'');',
'      if (data.length === 0) {',
'        container.innerHTML = ''<p>No hay eventos aun.</p>'';',
'        return;',
'      }',
'      container.innerHTML = data.map(e => `',
'        <div style="border:1px solid #ddd; border-radius:8px; padding:12px; margin-bottom:10px;">',
'          <strong>${e.nombre}</strong>',
'          ${Object.entries(e)',
'            .filter(([k]) => ![''_id'',''bar_id'',''nombre'',''fecha_creacion''].includes(k))',
'            .map(([k,v]) => `<p><b>${k}:</b> ${v}</p>`)',
'            .join('''')}',
'        </div>',
'      `).join('''');',
'    })',
'    .catch(() => {',
'      document.getElementById(''eventos-container'').innerHTML = ''<p>Error cargando eventos.</p>'';',
'    });',
'}',
'',
'function registrarEvento() {',
'  const nombre = apex.item(''P3_NOMBRE_EVENTO'').getValue();',
'  if (!nombre.trim()) {',
'    apex.message.showErrors([{ message: ''El nombre es obligatorio.'' }]);',
'    return;',
'  }',
'  const evento = { bar_id: barId, nombre: nombre };',
'  const opc1 = apex.item(''P3_CAMPO_OPC1'').getValue();',
'  const opc2 = apex.item(''P3_CAMPO_OPC2'').getValue();',
'  if (opc1.trim()) evento.artista = opc1;',
'  if (opc2.trim()) evento.cover = opc2;',
'',
'  fetch(`${API_BASE}/${barId}/eventos`, {',
'    method: ''POST'',',
'    headers: { ''Content-Type'': ''application/json'' },',
'    body: JSON.stringify(evento)',
'  })',
'  .then(res => res.json())',
'  .then(() => {',
'    apex.item(''P3_NOMBRE_EVENTO'').setValue('''');',
'    apex.item(''P3_CAMPO_OPC1'').setValue('''');',
'    apex.item(''P3_CAMPO_OPC2'').setValue('''');',
'    cargarEventos();',
'  });',
'}',
'',
'cargarComentarios();',
'cargarEventos();'))
