 p_id=>wwv_flow_imp.id(112210172222177116443)
,p_event_id=>wwv_flow_imp.id(112210172191801116442)
,p_event_result=>'TRUE'
,p_action_sequence=>10
,p_execute_on_page_init=>'N'
,p_action=>'NATIVE_JAVASCRIPT_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'const texto = apex.item(''P3_TEXTO_COMENTARIO'').getValue();',
'if (!texto.trim()) {',
'  apex.message.showErrors([{ message: ''El comentario no puede estar vacio.'' }]);',
'  return;',
'}',
'const barId = parseInt(apex.item(''P3_BAR_ID'').getValue());',
'fetch(''https://s9-g4-2026-1.onrender.com/bares/'' + barId + ''/comentarios'', {',
'  method: ''POST'',',
'  headers: { ''Content-Type'': ''application/json'' },',
'  body: JSON.stringify({ bar_id: barId, texto: texto, autor: apex.env.APP_USER })',
'})',
'.then(res => res.json())',
'.then(() => {',
'  apex.item(''P3_TEXTO_COMENTARIO'').setValue('''');',
'  cargarComentarios();',
'});'))
);
wwv_flow_imp_page.create_page_da_event(
 p_id=>wwv_flow_imp.id(112210172301194116444)
,p_name=>'Registrar evento'
,p_event_sequence=>30
,p_triggering_element_type=>'BUTTON'
,p_triggering_button_id=>wwv_flow_imp.id(112210171658090116437)
,p_bind_type=>'bind'
,p_execution_type=>'IMMEDIATE'
,p_bind_event_type=>'click'
);
wwv_flow_imp_page.create_page_da_action(
 p_id=>wwv_flow_imp.id(112210172403254116445)
,p_event_id=>wwv_flow_imp.id(112210172301194116444)
,p_event_result=>'TRUE'
,p_action_sequence=>10
,p_execute_on_page_init=>'N'
,p_action=>'NATIVE_JAVASCRIPT_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'const barId = parseInt(apex.item(''P3_BAR_ID'').getValue());',
'const nombre = apex.item(''P3_NOMBRE_EVENTO'').getValue();',
'if (!nombre.trim()) {',
'  apex.message.showErrors([{ message: ''El nombre es obligatorio.'' }]);',
'  return;',
'}',
'const evento = { bar_id: barId, nombre: nombre };',
'const opc1 = apex.item(''P3_CAMPO_OPC1'').getValue();',
'const opc2 = apex.item(''P3_CAMPO_OPC2'').getValue();',
'if (opc1.trim()) evento.artista = opc1;',
'if (opc2.trim()) evento.cover = opc2;',
'fetch(''https://s9-g4-2026-1.onrender.com/bares/'' + barId + ''/eventos'', {',
'  method: ''POST'',',
'  headers: { ''Content-Type'': ''application/json'' },',
'  body: JSON.stringify(evento)',
'})',
'.then(res => res.json())',
'.then(() => {',
'  apex.item(''P3_NOMBRE_EVENTO'').setValue('''');',
'  apex.item(''P3_CAMPO_OPC1'').setValue('''');',
'  apex.item(''P3_CAMPO_OPC2'').setValue('''');',
'  cargarEventos();',
'});'))
);
end;
